import React, { useEffect, useState } from 'react';
import { useLocation } from 'react-router-dom';

interface TenorGifProps {
  postId: string;
  aspectRatio?: number;
}

/**
 * Ensures window.Tenor is available before attempting to load GIFs.
 */
function loadTenor(): Promise<void> {
  return new Promise((resolve) => {
    if ((window as any).Tenor) return resolve();

    const check = setInterval(() => {
      if ((window as any).Tenor) {
        clearInterval(check);
        resolve();
      }
    }, 100);

    // Timeout safety after 5 seconds
    setTimeout(() => {
      clearInterval(check);
      resolve();
    }, 5000);
  });
}

const TenorGif: React.FC<TenorGifProps> = ({ postId, aspectRatio = 1 }) => {
  const [isLoaded, setIsLoaded] = useState(false);
  const location = useLocation();

  useEffect(() => {
    let isMounted = true;

    const initTenor = async () => {
      await loadTenor();

      if (!isMounted) return;

      setTimeout(() => {
        if ((window as any).Tenor && isMounted) {
          (window as any).Tenor.load();
          setIsLoaded(true);
        }
      }, 500);
    };

    initTenor();

    return () => {
      isMounted = false;
    };
  }, [postId, location.pathname, location.hash]);

  return (
    <div 
      key={`${postId}-${location.pathname}-${location.hash}`}
