import { useEffect, useRef, useState } from "react";
import { useLocation } from "react-router-dom";

export default function TenorGif({ postId }) {

  const ref = useRef(null);
  const location = useLocation();
  const [ready, setReady] = useState(false);

  useEffect(() => {

    let retry = 0;

    function tryLoad() {

      if (window.Tenor && ref.current) {

        window.Tenor.load();

        setTimeout(() => {

          const iframe = ref.current.querySelector("iframe");

          if (iframe) {
            setReady(true);
          } else if (retry < 10) {
            retry++;
            setTimeout(tryLoad, 500);
          }

        }, 500);

      } else if (retry < 10) {
        retry++;
        setTimeout(tryLoad, 500);
      }
    }

    tryLoad();

  }, [postId, location.pathname]);

  return (
    <div className="gif-wrapper">

      {!ready && (
        <div className="gif-loader">
          Loading love...
        </div>
      )}

      <div
        ref={ref}
        key={postId + location.pathname}
        className="tenor-gif-embed"
        data-postid={postId}
        data-share-method="host"
        data-aspect-ratio="1"
        data-width="100%"
      />

    </div>
  );
}

