import React, { useEffect, useRef, useState } from "react";
import { useLocation } from "react-router-dom";

interface TenorGifProps {
  postId: string;
}

export default function TenorGif({ postId }: TenorGifProps) {
  const ref = useRef<HTMLDivElement>(null);
  const location = useLocation();
  const [ready, setReady] = useState(false);

  useEffect(() => {
    let retry = 0;
    let isMounted = true;

    function tryLoad() {
      if (!isMounted) return;

      const tenor = (window as any).Tenor;

      if (tenor && ref.current) {
        tenor.load();

        setTimeout(() => {
          if (!isMounted || !ref.current) return;
          const iframe = ref.current.querySelector("iframe");

          if (iframe) {
            setReady(true);
          } else if (retry < 10) {
            retry++;
            setTimeout(tryLoad, 500);
          }
        }, 500);
      } else if (retry < 10) {
        retry++;
        setTimeout(tryLoad, 500);
      }
    }

    setReady(false);
    tryLoad();

    return () => {
      isMounted = false;
    };
  }, [postId, location.pathname, location.hash]);

  return (
    <div className="gif-wrapper">
      {!ready && (
        <div className="gif-loader">
          <div className="flex flex-col items-center gap-2">
            <span className="text-xl">💗</span>
            <span className="text-[10px] uppercase font-bold tracking-widest">Loading love...</span>
          </div>
        </div>
      )}

      <div
        ref={ref}
        key={postId + location.pathname + location.hash}
        className="tenor-gif-embed"
        data-postid={postId}
        data-share-method="host"
        data-aspect-ratio="1"
        data-width="100%"
      >
        <a href={`https://tenor.com/view/${postId}`}>GIF</a>
      </div>
    </div>
  );
}
